<ref>{{Cite web |title=Basic Terms of Shinto: Shinkai |url=https://www2.kokugakuin.ac.jp/ijcc/wp/bts/bts_s.html |access-date=2023-11-11 |website=www2.kokugakuin.ac.jp}}</ref>
